mapper.select:
SELECT s.SET_ID, s.FOLDER_ID, f.FOLDER_NAME AS folderName, s.SET_NAME, s.DESCRIPTION, s.DISPLAY_ORDER, s.IS_ACTIVE, s.CREATED_AT, s.UPDATED_AT FROM TB_SENTENCE_SET s LEFT JOIN TB_FOLDER f ON f.FOLDER_ID = s.FOLDER_ID AND f.MEMBER_ID = s.MEMBER_ID AND f.IS_ACTIVE = 'Y' WHERE s.MEMBER_ID = #{memberId} AND s.IS_ACTIVE = 'Y'
AND s.FOLDER_ID = #{folderId, jdbcType=NUMERIC}
ORDER BY s.DISPLAY_ORDER ASC, s.SET_ID DESC

SELECT COUNT(*)
FROM TB_SENTENCE_SET
WHERE SET_ID = #{setId}
  AND MEMBER_ID = #{memberId}
  AND IS_ACTIVE = 'Y'
